    "commentarySections": [
      {
        "id": "historical-background",
        "label": {
          "zh": "历史背景",
          "en": "Historical Background"
        },
        "html": {
          "zh": "R-CNN 已经大幅提升目标检测精度，但外部候选区域生成让流水线变慢且不够统一。 这段背景帮助观众把Faster R-CNN放回当时的技术问题和研究重点中理解。",
          "en": "Object detection had made large accuracy gains with R-CNN, but external proposal generation made the pipeline slower and less elegant. This context helps viewers place Faster R-CNN in the technical problems and research priorities of its time."
        },
        "sourceIds": [
          "source-faster-r-cnn-towards-real-time-object-detection-with-region-proposal-networks"
        ]
      },
      {
        "id": "core-idea",
        "label": {
          "zh": "核心思想",
          "en": "Core Idea"
        },
        "html": {
          "zh": "Faster R-CNN 让网络在计算视觉特征的同时学习提出候选框。检测因此成为学习型流水线，而不是无关模块之间的交接。",
          "en": "Faster R-CNN trains the network to propose boxes while it is already computing visual features. Detection becomes a learned pipeline rather than a hand-off between unrelated modules."
        },
        "sourceIds": [
          "source-faster-r-cnn-towards-real-time-object-detection-with-region-proposal-networks"
        ]
      },
      {
        "id": "long-term-legacy",
        "label": {
          "zh": "长期影响",
          "en": "Long-Term Legacy"
        },
        "html": {
          "zh": "专家通常把 Faster R-CNN 视为让目标检测更端到端、更可学习的转折点。它的长期影响在于“候选区域 + 识别”框架仍塑造着研究者对精度、速度和定位权衡的解释。",
          "en": "Experts generally treat Faster R-CNN as a turning point that made object detection more end-to-end and learnable. Its long-term legacy is the proposal-and-recognition framework that still shapes how researchers explain accuracy, speed, and localization tradeoffs."
        },
        "sourceIds": [
          "source-faster-r-cnn-towards-real-time-object-detection-with-region-proposal-networks"
        ]
      }
    ],
