    "commentarySections": [
      {
        "id": "historical-background",
        "label": {
          "zh": "历史背景",
          "en": "Historical Background"
        },
        "html": {
          "zh": "到 1970 年代初，符号 AI 需要能表达规则、关系和搜索的语言，而不是把它们埋在过程式代码里。 这段背景帮助观众把PROLOG放回当时的技术问题和研究重点中理解。",
          "en": "By the early 1970s, symbolic AI needed languages that could express rules, relations, and search without burying them under procedural code. This context helps viewers place PROLOG in the technical problems and research priorities of its time."
        },
        "sourceIds": [
          "source-the-birth-of-prolog"
        ]
      },
      {
        "id": "core-idea",
        "label": {
          "zh": "核心思想",
          "en": "Core Idea"
        },
        "html": {
          "zh": "Prolog 程序是关系数据库。查询求值变成对逻辑后果的受控搜索。",
          "en": "A Prolog program is a database of relations. Query evaluation becomes a controlled search through logical consequences."
        },
        "sourceIds": [
          "source-the-birth-of-prolog"
        ]
      },
      {
        "id": "long-term-legacy",
        "label": {
          "zh": "长期影响",
          "en": "Long-Term Legacy"
        },
        "html": {
          "zh": "专家通常把 Prolog 视为逻辑程序设计和声明式计算的标志性成果。它的长期影响在于证明事实、规则、合一和回溯可以组成可执行推理系统。",
          "en": "Experts generally treat Prolog as a landmark in logic programming and declarative computation. Its long-term legacy is the durable idea that facts, rules, unification, and backtracking can form an executable reasoning system."
        },
        "sourceIds": [
          "source-the-birth-of-prolog"
        ]
      }
    ],
    "analysis": null,
