    "commentarySections": [
      {
        "id": "historical-background",
        "label": {
          "zh": "历史背景",
          "en": "Historical Background"
        },
        "html": {
          "zh": "20 世纪 60 年代，AI 语言系统多为手工构建的符号系统。ELIZA 测试少量脚本能否维持自然对话的印象。",
          "en": "In the 1960s, AI language systems were mostly symbolic and hand-built. ELIZA tested whether a small set of scripts could sustain the impression of natural conversation."
        },
        "sourceIds": [
          "source-eliza-cacm-paper"
        ]
      },
      {
        "id": "core-idea",
        "label": {
          "zh": "核心思想",
          "en": "Core Idea"
        },
        "html": {
          "zh": "DOCTOR 脚本并不理解心理治疗；它把识别到的模式转成反问式提示，诱导用户继续说下去。 关键机制是模式匹配与脚本反射，它把资料线索与可见的演示行为连接起来。",
          "en": "The DOCTOR script does not understand therapy; it transforms recognized patterns into reflective prompts that invite the user to continue. The key mechanism is Pattern matching and scripted reflection, which links the source material to the visible demo behavior."
        },
        "sourceIds": [
          "source-eliza-cacm-paper"
        ]
      },
      {
        "id": "long-term-legacy",
        "label": {
          "zh": "长期影响",
          "en": "Long-Term Legacy"
        },
        "html": {
          "zh": "专家通常认为 ELIZA 既具有历史重要性，也具有警示意义：它没有深层理解，却能制造对话幻觉。它的长期影响在于提醒人们，交互设计、期待和用户投射会强烈影响对 AI 的判断。",
          "en": "Experts generally treat ELIZA as both historically important and cautionary: it produced conversational illusion without deep understanding. Its long-term legacy is the reminder that interaction design, expectation, and user projection strongly shape judgments about AI."
        },
        "sourceIds": [
          "source-eliza-cacm-paper"
        ]
      }
    ],
    "analysis": null,
