    "commentarySections": [
      {
        "id": "historical-background",
        "label": {
          "zh": "历史背景",
          "en": "Historical Background"
        },
        "html": {
          "zh": "Word2Vec 之前，许多 NLP 系统依赖稀疏计数或手工特征。Word2Vec 让密集向量在网页规模上变得实用。",
          "en": "Before word2vec, many NLP systems relied on sparse counts or hand-built features. Word2vec made dense vectors practical at web scale."
        },
        "sourceIds": [
          "source-efficient-estimation-of-word-representations-in-vector-space"
        ]
      },
      {
        "id": "core-idea",
        "label": {
          "zh": "核心思想",
          "en": "Core Idea"
        },
        "html": {
          "zh": "模型要么由词预测上下文，要么由上下文预测词，从而迫使相关词占据向量空间的相近区域。 关键机制是Skip-gram 与 CBOW 神经词嵌入，它把资料线索与可见的演示行为连接起来。",
          "en": "The model predicts context from a word or a word from context, forcing related words to occupy nearby regions of vector space. The key mechanism is Skip-gram and CBOW neural word embeddings, which links the source material to the visible demo behavior."
        },
        "sourceIds": [
          "source-efficient-estimation-of-word-representations-in-vector-space"
        ]
      },
      {
        "id": "long-term-legacy",
        "label": {
          "zh": "长期影响",
          "en": "Long-Term Legacy"
        },
        "html": {
          "zh": "专家通常把 Word2Vec 视为基础性的嵌入方法，它让分布式语义能够规模化运行。它的长期影响在于意义的几何观仍影响检索、表示学习和向量数据库。",
          "en": "Experts generally treat Word2Vec as a foundational embedding method that made distributional semantics operational at scale. Its long-term legacy is the geometric view of meaning that still informs retrieval, representation learning, and vector databases."
        },
        "sourceIds": [
          "source-efficient-estimation-of-word-representations-in-vector-space"
        ]
      }
    ],
