    "commentarySections": [
      {
        "id": "historical-background",
        "label": {
          "zh": "历史背景",
          "en": "Historical Background"
        },
        "html": {
          "zh": "早期语言程序往往只处理孤立句子。SHRDLU 让语言、指称、记忆和动作共享同一个微型世界。",
          "en": "Early language programs often handled isolated sentences. SHRDLU made language, reference, memory, and action share one miniature world."
        },
        "sourceIds": [
          "source-procedures-as-a-representation-for-data-in-a-computer-program-for-understanding-"
        ]
      },
      {
        "id": "core-idea",
        "label": {
          "zh": "核心思想",
          "en": "Core Idea"
        },
        "html": {
          "zh": "系统通过积木、空间关系和可以改变场景的过程来落地理解用户话语。 关键机制是积木世界语言理解，它把资料线索与可见的演示行为连接起来。",
          "en": "The system understood utterances by grounding them in blocks, spatial relations, and procedures that could actually change the scene. The key mechanism is Blocks-world language understanding, which links the source material to the visible demo behavior."
        },
        "sourceIds": [
          "source-procedures-as-a-representation-for-data-in-a-computer-program-for-understanding-"
        ]
      },
      {
        "id": "long-term-legacy",
        "label": {
          "zh": "长期影响",
          "en": "Long-Term Legacy"
        },
        "html": {
          "zh": "专家通常把 SHRDLU 视为微世界 AI 的希望与脆弱性的经典展示。它的长期影响在于说明语言理解在受限世界模型中可以显得很强大，同时也暴露了这种限制本身的边界。",
          "en": "Experts generally treat SHRDLU as a classic demonstration of both the promise and brittleness of microworld AI. Its long-term legacy is showing that language understanding can look powerful when grounded in a tightly constrained world model, while also exposing the limits of that constraint."
        },
        "sourceIds": [
          "source-procedures-as-a-representation-for-data-in-a-computer-program-for-understanding-"
        ]
      }
    ],
    "analysis": null,
