    "commentarySections": [
      {
        "id": "historical-background",
        "label": {
          "zh": "历史背景",
          "en": "Historical Background"
        },
        "html": {
          "zh": "符号 AI 难以处理不确定性。概率图模型把知识表示与统计推断连接起来。",
          "en": "Symbolic AI struggled with uncertainty. Probabilistic graphical models connected knowledge representation with statistical inference."
        },
        "sourceIds": [
          "source-bayesian-networks"
        ]
      },
      {
        "id": "core-idea",
        "label": {
          "zh": "核心思想",
          "en": "Core Idea"
        },
        "html": {
          "zh": "贝叶斯网络按有向无环图分解联合分布，使推断模块化。 关键机制是有向无环图加条件概率，它把资料线索与可见的演示行为连接起来。",
          "en": "A Bayesian network factorizes a joint distribution according to a directed acyclic graph, making inference modular. The key mechanism is Directed acyclic graph plus conditional probabilities, which links the source material to the visible demo behavior."
        },
        "sourceIds": [
          "source-bayesian-networks"
        ]
      },
      {
        "id": "long-term-legacy",
        "label": {
          "zh": "长期影响",
          "en": "Long-Term Legacy"
        },
        "html": {
          "zh": "专家通常把贝叶斯网络视为不确定推理的基础语言。它的长期影响在于用图结构连接概率、证据和依赖关系，并影响了后来的因果推理和决策支持。",
          "en": "Experts generally treat Bayesian networks as a foundational language for uncertain reasoning. Their long-term legacy is the graphical connection between probability, evidence, and dependency structure, which later influenced causal reasoning and decision support."
        },
        "sourceIds": [
          "source-bayesian-networks"
        ]
      }
    ],
